UPDATE curriculum_readings SET passage_content = '{"paragraphs": ["Riyadh is a big *capital* city. Many people live here. Every *morning*, they wake up and start the day. Some people drive to work. Others take the bus. The *streets* are busy with many cars.", "People go to *shops* and *restaurants* for *lunch*. The food is very good. You can find many *buildings* and nice places in the city. There are parks and markets too.", "In the *evening*, the city is *beautiful*. Families go to parks and walk together. Children play and have fun. People drink tea and talk. Life in Riyadh is *interesting* every day. It is a wonderful place to live."]}'::jsonb, passage_word_count = 103, updated_at = NOW() WHERE id = '3bb6f744-6dc9-46b5-a7f1-6651475d5484' RETURNING id, reading_label;